#include <stdio.h>
int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int cards[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &cards[i]);
    }
    int operations = 0;
    int ops[N];
    for (int i = 0; i < N; i++) {
        if (cards[i] < 0) {
            ops[operations++] = i + 1;
            cards[i] *= -1;
            if (i + 1 < N) {
                cards[i + 1] *= -1;
            }
        }
    }
    printf("%d\n", operations);
    for (int i = 0; i < operations; i++) {
        printf("%d ", ops[i]);
    }
    return 0;
}

